const output = $input.first().json.text || '';

const resumeMatch = output.match(
  /TAILORED_RESUME_START([\s\S]*?)TAILORED_RESUME_END/
);
const atsMatch = output.match(/ATS_SCORE:\s*(\d+)/);
const addedMatch = output.match(/KEYWORDS_ADDED:\s*([^\n]+)/);
const missingMatch = output.match(/KEYWORDS_MISSING:\s*([^\n]+)/);

return [{
  json: {
    tailoredResume: resumeMatch ? resumeMatch[1].trim() : output,
    atsScore: atsMatch ? atsMatch[1] + '%' : 'N/A',
    keywordsAdded: addedMatch ? addedMatch[1].trim() : '',
    keywordsMissing: missingMatch ? missingMatch[1].trim() : '',
    companyName: $('Webhook').first().json.body.companyName,
    targetRole: $('Webhook').first().json.body.targetRole
  }
}];
